from flask import Flask, request, jsonify
import jwt
from jwt import PyJWTError

class JWTWrapper:
    def __init__(self, secret_key, public_key=None):
        self.secret_key = secret_key
        self.public_key = public_key

    def encode(self, payload, algorithm='HS256'):
        if algorithm.startswith('HS'):
            return jwt.encode(payload, self.secret_key, algorithm=algorithm)
        elif algorithm.startswith('RS') and self.public_key:
            return jwt.encode(payload, self.public_key, algorithm=algorithm)
        else:
            raise ValueError("Unsupported algorithm or missing public key for RS algorithms")

    def decode(self, token, algorithms=['HS256', 'RS256']):
        try:
            if 'RS' in algorithms and self.public_key:
                return jwt.decode(token, self.public_key, algorithms=algorithms)
            return jwt.decode(token, self.secret_key, algorithms=algorithms)
        except PyJWTError as e:
            raise ValueError(f"Token verification failed: {str(e)}")

app = Flask(__name__)

# Example usage
secret_key = 'your_hs256_secret_key'
public_key = 'your_rs256_public_key'

jwt_wrapper = JWTWrapper(secret_key, public_key)

@app.route('/verify', methods=['POST'])
def verify_token():
    token = request.json.get('token')
    try:
        payload = jwt_wrapper.decode(token)
        return jsonify({'status': 'success', 'payload': payload}), 200
    except ValueError as e:
        return jsonify({'status': 'error', 'message': str(e)}), 400

